content:
a.last_seen))
        });
        topics.truncate(limit);
        topics
    }

    /// Get all raw gap signals (for debugging/export).
    pub fn all_signals(&self) -> Vec<GapSignal> {
        self.signals.lock().unwrap().iter().cloned().collect()
    }
